After chatting on IRC, we got the following code working:

``// index.php

<div class="wrapper">
	<div class="insertData" data-table="0"></div>
	<div id="pager" class="pager">
		<img src="../tablesorter-master/addons/pager/icons/first.png" class="first"/>
		<img src="../tablesorter-master/addons/pager/icons/prev.png" class="prev"/>
		<span class="pagedisplay"></span>
		<img src="../tablesorter-master/addons/pager/icons/next.png" class="next"/>
		<img src="../tablesorter-master/addons/pager/icons/last.png" class="last"/>
		<select class="pagesize" title="Select page size">
			<option value="30" selected="selected">30</option>
			<option value="40">40</option>
			<option value="50">50</option>
			<option value="100">100</option>
		</select>
		<select class="gotoPage" title="Select page number"></select>
	</div>
</div>

<script>
$(function () { 

	var $wrapper = $('.insertData'),

	initializeTablesorter = function() {
		$wrapper.find('table').tablesorter({
			theme: "blue",
			widthFixed: true,
			headerTemplate: '{content} {icon}',
			widgets: ["column", "cssStickyHeaders", "filter", "zebra"],
			widgetOptions: {
				cssStickyHeaders_attachTo : '.wrapper', // or $('.wrapper'
			}
		}).tablesorterPager({
			container: '.pager',
			cssGoto: ".pagenum",
			output: '{startRow} - {endRow} / {filteredRows} ({totalRows})'
		});
	};

	$('#pageView').change(function () {
		// clean up previous table
		$wrapper
			.find('table')
			.trigger('destroy')
			.trigger('destroyPager')
			.empty()
			.hide();
		// get new stuff
		$wrapper.load( 'content/' + $(this).val() + '.php', function(){
			// new table loaded, now initialize
			initializeTablesorter();
		});
	})
	// initialize
	.val( 'table0' )
	.change();

});

</script>
```

