The problem is you attempt to use multiple `FlaskInjector` instances with different Injector configuration with a single Flask application, that won't work (we should probably raise a runtime exception when we detect that as it should be simple enough).

The natural way to approach this would be to not have a single global `Flask` instance but create one whenever necessary (different instance to actually serve the application, different instance(s) for testing):

```python
from abc import ABC, abstractmethod
from unittest import TestCase
from unittest.mock import MagicMock

from flask import Flask
from flask.json import jsonify
from flask.views import MethodView
from flask_injector import FlaskInjector
from injector import inject

class ServiceInterface(ABC):
    @abstractmethod
    def do_action(self) -> str:
        pass

class Endpoints(MethodView):
    @inject
    def __init__(self, service: ServiceInterface):
        self.service = service

    def get(self):
        return jsonify(self.service.do_action())

class Test(TestCase):
    def conf(self, binder):
        self.srv_mock = MagicMock(autospec=ServiceInterface)
        binder.bind(ServiceInterface, self.srv_mock)

    def setUp(self):
        self.app = create_app(injector_modules=[self.conf])
        self.app.testing = True
        self.client = app.test_client()

    def test_mock(self):
        self.srv_mock.do_action.return_value = 'test'
        r = self.client.get('/endpoint/')
        self.assertEqual(r.status_code, 200)

def configure_bindings(binder):
    # You really need to bind the interface to some implementation here
    binder.bind(ServiceInterface, to=IMPLEMENTATION)

def create_app(injector_modules=None):
    app = Flask('app')
    app.add_url_rule('/endpoint/', view_func=Endpoints.as_view('ep'), methods=['GET',])
    injector_modules = injector_modules or [configure_bindings]
    FlaskInjector(app=app, modules=injector_modules)
```

