An issue that comes up when using `fields.Method/Function` is that from that point on all "magic" that comes with `fields.Nested` is now a reponsibility of the method/function. Example:

```python
class ItemSchema(Schema):
    id = fields.String(required=True)
    type = fields.String(validate=OneOf(['normal', 'special']))

class ContentSchema(Schema):
    items = fields.Nested(ItemSchema, load_from='item_array', many=True)

# vs.

class WeirdContentSchema(Schema):
    items = fields.Method('load_items', many=True)
    def load_items(self, obj):
        # ...some custom logic that cannot utilize `ItemSchema`
        # usually re-inventing what `fields.Nested` does...
        return {...}

# vs. (not possible atm)

class WeirdContentSchema(Schema):
    items = fields.Nested(ItemSchema, load_from='foo.item_array', many=True)
```

I've come across such cases noumerous times when consuming "verbose/deeply-nested" APIs and every time there's a different hack involved using `@pre_load`, `fields.Methods` and the likes. 

Is there some cleaner way to load something `ItemSchema`, while keeping validation errors?

@sloria actually the approach I took similar to @anuragagarwal561994 above for flask... 

```
from marshmallow_jsonapi import fields, utils as mjutils

class LazyRelationship(fields.Relationship):
    """
    dont access the property unless the client actually wants to include it
    """
    @property
    def just_links(self):
        return not self.include_data

    def __old_get_id(self, value):
        """
        super not working for some reason so HACK
        """
        if mjutils._MARSHMALLOW_VERSION_INFO[0] >= 3:
            if self.schema:
                return self.schema.get_attribute(value, self.id_field, value)
            else:
                return fields.get_value(value, self.id_field, value)
        else:
            if self.schema:
                return self.schema.get_attribute(self.id_field, value, value)
            else:
                return fields.get_value(value, self.id_field, value)

    def _get_id(self, value):
        if self.just_links:
            return value

        return self.__old_get_id(value)


    def get_value(self, f1_, f2_, accessor=None, default=mjutils.missing):
        if mjutils._MARSHMALLOW_VERSION_INFO[0] >= 3:
            obj = f1_
            attr = f2_
        else:
            obj = f2_
            attr = f1_

        if obj is None:
            return mjutils.missing

        if not getattr(self, 'include_data', False) and not getattr(self, 'include_resource_linkage', False):
            return None

        if self.just_links:
            # original get_value method prioritizes `attribute` key
            # thus we override it to prioritize `id_attribute` over `attribute`
            attribute = getattr(self, 'id_attribute', None)
            accessor_func = accessor or mjutils._get_value

            if mjutils._MARSHMALLOW_VERSION_INFO[0] >= 3:
                return accessor_func(obj, attribute, default)

            return accessor_func(attribute, obj, default)

        if mjutils._MARSHMALLOW_VERSION_INFO[0] >= 3:
            super(fields.Relationship, self).get_value(obj, attr, accessor, default)

        return \
            super(fields.Relationship, self).get_value(attr, obj, accessor, default)
```

I'm considering the following change, in which `infer_dc_model` is always followed by the logic in `dc_model` to validate the parameters.  To me this is better than having `infer_dc_model` do its own consistency check on the full parameter list.

`    def dc_model(self, model):

       # guess at model if None
        if model is None:
            self._dc_model, model = self.infer_dc_model()
        # Set model and validate parameters
        if isinstance(model, str):
            model = model.lower()
            # validate module parameters
            missing_params = DC_MODEL_PARAMS[model] - \
                                    set(self.system.module_parameters.keys())
            if missing_params: # some parameters are not in module.keys()
                raise ValueError(model + ' selected for the DC model but '
                                     'one or more required parameters '
                                     ' are missing : ' +
                                     str(missing_params))
            if model == 'sapm':
                self._dc_model = self.sapm
            elif model == 'singlediode':
                self._dc_model = self.singlediode
            elif model == 'pvwatts':
                self._dc_model = self.pvwatts_dc
            else:
                raise ValueError(model + ' is not a valid DC power model')
        else:
            self._dc_model = partial(model, self)

    def infer_dc_model(self):
        # returns both model function object and model string, could drop
        # model function object in the future since the model function object
        # will be set in dc_model after validating parameter consistency
        params = set(self.system.module_parameters.keys())
        if set(['A0', 'A1', 'C7']) <= params:
            return self.sapm, 'sapm'
        elif set(['a_ref', 'I_L_ref', 'I_o_ref', 'R_sh_ref', 'R_s']) <= params:
            return self.singlediode, 'singlediode'
        elif set(['pdc0', 'gamma_pdc']) <= params:
            return self.pvwatts_dc, 'pvwatts_dc'
        else:
            raise ValueError('could not infer DC model from '
                             'system.module_parameters')

`

